DROP TABLE IF EXISTS `equipe`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipe` (
  `id_equipe` int NOT NULL AUTO_INCREMENT,
  `id_clube` int NOT NULL,
  `id_modalidade` int NOT NULL,
  `id_categoria` int NOT NULL,
  `genero` varchar(10) NOT NULL,
  `nome` varchar(140) NOT NULL,
  PRIMARY KEY (`id_equipe`),
  KEY `id_clube` (`id_clube`),
  KEY `id_modalidade` (`id_modalidade`),
  KEY `id_categoria` (`id_categoria`),
  CONSTRAINT `equipe_ibfk_1` FOREIGN KEY (`id_clube`) REFERENCES `clube` (`id_clube`),
  CONSTRAINT `equipe_ibfk_2` FOREIGN KEY (`id_modalidade`) REFERENCES `modalidade` (`id_modalidade`),
  CONSTRAINT `equipe_ibfk_3` FOREIGN KEY (`id_categoria`) REFERENCES `categoria` (`id_categoria`)
) ENGINE=InnoDB AUTO_INCREMENT=181 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
